#!/usr/bin/env bash
# Verify that all target plugin files exist before sprint work begins.
# Generated by the initializer agent — edit to match your project.
set -e

PROJECT_ROOT="$(cd "$(dirname "$0")/.." && pwd)"

FILES=(
  "plugins/harness/agents/evaluator.md"
  "plugins/harness/agents/coordinator.md"
  "plugins/harness/skills/harness/SKILL.md"
  "plugins/harness/skills/harness/references/patterns.md"
  "plugins/harness/skills/harness/roles/evaluator.md"
  "plugins/harness/skills/harness/roles/coordinator.md"
)

PASS=0
FAIL=0

for f in "${FILES[@]}"; do
  if [ -f "$PROJECT_ROOT/$f" ]; then
    echo "OK — $f"
    PASS=$((PASS + 1))
  else
    echo "FAIL — $f not found"
    FAIL=$((FAIL + 1))
  fi
done

echo ""
echo "Result: $PASS passed, $FAIL failed out of ${#FILES[@]} files"

if [ "$FAIL" -gt 0 ]; then
  echo "FAIL — missing target files; cannot proceed with sprints"
  exit 1
else
  echo "OK — all target files present; ready for sprint 1"
fi
